def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 11):
            weight = (11 - j) / 55
            term = (ratio ** j) * weight
            if j % 2 == 0:
                term *= 1.2
            else:
                term *= 0.8
            score += term
        if capacity > 3 * item:
            score *= 0.4
        elif capacity > 2 * item:
            score *= 0.7
        elif capacity < item:
            score *= 2.5
        else:
            for k in range(1, 4):
                if (capacity - k * item) >= 0 and (capacity - k * item) < item:
                    score *= 1 + 0.1 * k
                    break
        if score < 0.1:
            score += 0.1
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1.0
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 15
    return priorities
